// Get questions for a specific set
export const getSetQuestions = (setId: number): SAPQuestion[] => {
  const set = EXAM_SETS.find(s => s.id === setId);
  if (!set) return [];
  return SAP_QUESTIONS.slice(set.startIndex, set.startIndex + set.questions);
};

// Get question count for a set
export const getSetQuestionCount = (setId: number): number => {
  const set = EXAM_SETS.find(s => s.id === setId);
  if (!set) return 0;
  const actualCount = Math.min(set.questions, SAP_QUESTIONS.length - set.startIndex);
  return actualCount > 0 ? actualCount : 0;
};

