import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Layout from '../components/Layout';
import { getAllRecords, fmtDate } from '../utils/storage';
import { ExamSubmission } from '../types';

const UserDashboard: React.FC = () => {
  const navigate = useNavigate();
  const [resultFilter, setResultFilter] = useState<'all' | 'pass' | 'needswork'>('all');
  const [dateFrom, setDateFrom] = useState<string>('');
  const [dateTo, setDateTo] = useState<string>('');
  const [examSetFilter, setExamSetFilter] = useState<string>('all');
  
  useEffect(() => {
    const isLoggedIn = sessionStorage.getItem('userLoggedIn') === '1';
    if (!isLoggedIn) {
      navigate('/login', { replace: true });
    }
  }, [navigate]);
  
  const isLoggedIn = sessionStorage.getItem('userLoggedIn') === '1';
  const exams = getAllRecords('exam_submissions') as unknown as ExamSubmission[];
  const dashUser = sessionStorage.getItem('dashUser') || 'User';

  if (!isLoggedIn) {
    return null;
  }

  const filteredExams = exams.filter(e => {
    const pct = Math.round((e.score / e.total) * 100);
    
    // Result filter
    if (resultFilter === 'pass' && pct < 80) return false;
    if (resultFilter === 'needswork' && pct >= 80) return false;
    
    // Date filter
    if (dateFrom || dateTo) {
      const examTs = e._timestamp;
      if (!examTs) return false;
      const examDate = new Date(examTs);
      if (dateFrom && examDate < new Date(dateFrom)) return false;
      if (dateTo && examDate > new Date(dateTo + 'T23:59:59')) return false;
    }
    
    return true;
  });

  return (
    <Layout>
      <div style={{ padding: '40px 5%', background: 'var(--gray-50)', minHeight: 'calc(100vh - 64px)' }}>
        <div className="container" style={{ maxWidth: '1100px' }}>
          <div style={{ background: 'linear-gradient(135deg, var(--blue-pale), var(--orange-pale))', border: '1px solid var(--gray-200)', borderRadius: 'var(--radius-lg)', padding: '32px', marginBottom: '24px', textAlign: 'center' }}>
            <div style={{ fontSize: '2.4rem', marginBottom: '8px' }}>🎉</div>
            <h1 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--gray-800)', marginBottom: '6px' }}>Welcome, <span style={{ color: 'var(--blue)' }}>{dashUser}</span>!</h1>
            <p style={{ color: 'var(--gray-600)' }}>Your full exam bank is now unlocked. Happy learning!</p>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px,1fr))', gap: '20px', marginBottom: '28px' }}>
            <div style={{ background: '#fff', border: '1.5px solid var(--gray-200)', borderRadius: 'var(--radius)', padding: '24px', textAlign: 'center', boxShadow: 'var(--shadow-sm)' }}>
              <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🏗️</div>
              <h3 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '8px' }}>SAP-C02 Exam</h3>
              <p style={{ fontSize: '0.9rem', color: 'var(--gray-500)', marginBottom: '16px' }}>AWS Solutions Architect Professional</p>
              <div style={{ display: 'flex', gap: '12px', justifyContent: 'center' }}>
                <Link to="/sap-exam?mode=practice" className="btn btn-orange btn-sm">Practice</Link>
                <Link to="/sap-exam?mode=exam" className="btn btn-blue btn-sm">SAP Exam</Link>
              </div>
            </div>
          </div>

          <div style={{ marginBottom: '20px' }}>
            <h2 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--gray-800)', marginBottom: '14px' }}>📊 My Exam History</h2>
            
            <div style={{ display: 'flex', gap: '12px', marginBottom: '12px', flexWrap: 'wrap', alignItems: 'center' }}>
              {/* Result Filters */}
              <button onClick={() => setResultFilter('all')} style={{ padding: '6px 12px', borderRadius: '16px', border: resultFilter === 'all' ? '2px solid var(--blue)' : '1px solid var(--gray-300)', background: resultFilter === 'all' ? 'var(--blue)' : '#fff', color: resultFilter === 'all' ? '#fff' : 'var(--gray-700)', cursor: 'pointer', fontSize: '0.8rem' }}>All</button>
              <button onClick={() => setResultFilter('pass')} style={{ padding: '6px 12px', borderRadius: '16px', border: resultFilter === 'pass' ? '2px solid var(--green)' : '1px solid var(--gray-300)', background: resultFilter === 'pass' ? 'var(--green)' : '#fff', color: resultFilter === 'pass' ? '#fff' : 'var(--gray-700)', cursor: 'pointer', fontSize: '0.8rem' }}>Pass</button>
              <button onClick={() => setResultFilter('needswork')} style={{ padding: '6px 12px', borderRadius: '16px', border: resultFilter === 'needswork' ? '2px solid var(--red)' : '1px solid var(--gray-300)', background: resultFilter === 'needswork' ? 'var(--red)' : '#fff', color: resultFilter === 'needswork' ? '#fff' : 'var(--gray-700)', cursor: 'pointer', fontSize: '0.8rem' }}>Needs Work</button>
              
              <span style={{ color: 'var(--gray-400)', margin: '0 4px' }}>|</span>
              
              {/* Date from */}
              <label style={{ fontSize: '0.8rem', color: 'var(--gray-600)' }}>From:</label>
              <input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} style={{ padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--gray-300)', fontSize: '0.8rem' }} />
              
              <label style={{ fontSize: '0.8rem', color: 'var(--gray-600)' }}>To:</label>
              <input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} style={{ padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--gray-300)', fontSize: '0.8rem' }} />
              
              <span style={{ color: 'var(--gray-400)', margin: '0 4px' }}>|</span>
              
              {/* Set Filters */}
              <button onClick={() => setExamSetFilter('all')} style={{ padding: '6px 12px', borderRadius: '16px', border: examSetFilter === 'all' ? '2px solid var(--blue)' : '1px solid var(--gray-300)', background: examSetFilter === 'all' ? 'var(--blue)' : '#fff', color: examSetFilter === 'all' ? '#fff' : 'var(--gray-700)', cursor: 'pointer', fontSize: '0.8rem' }}>All Sets</button>
              <button onClick={() => setExamSetFilter('1')} style={{ padding: '6px 12px', borderRadius: '16px', border: examSetFilter === '1' ? '2px solid var(--blue)' : '1px solid var(--gray-300)', background: examSetFilter === '1' ? 'var(--blue)' : '#fff', color: examSetFilter === '1' ? '#fff' : 'var(--gray-700)', cursor: 'pointer', fontSize: '0.8rem' }}>Set 1</button>
            </div>
            
            <div style={{ maxHeight: '300px', overflowY: 'auto', overflowX: 'hidden' }}>
              {filteredExams.length === 0 ? (
                <div className="empty-state">
                  <div className="es-icon">📭</div>
                  <p>No exams taken yet. <Link to="/sap-exam?mode=practice" style={{ color: 'var(--blue)', fontWeight: 700 }}>Take your first exam →</Link></p>
                </div>
              ) : (
                <div style={{ overflowX: 'auto' }}>
                  <table style={{ borderCollapse: 'collapse', width: '100%' }}>
                    <thead style={{ position: 'sticky', top: 0, background: '#fff', zIndex: 1 }}>
                      <tr>
                        <th style={{ padding: '12px 8px', textAlign: 'left', borderBottom: '2px solid var(--gray-200)', background: 'var(--gray-50)', fontWeight: 600, fontSize: '0.8rem' }}>Date</th>
                        <th style={{ padding: '12px 8px', textAlign: 'left', borderBottom: '2px solid var(--gray-200)', background: 'var(--gray-50)', fontWeight: 600, fontSize: '0.8rem' }}>Exam Set</th>
                        <th style={{ padding: '12px 8px', textAlign: 'left', borderBottom: '2px solid var(--gray-200)', background: 'var(--gray-50)', fontWeight: 600, fontSize: '0.8rem' }}>Category</th>
                        <th style={{ padding: '12px 8px', textAlign: 'left', borderBottom: '2px solid var(--gray-200)', background: 'var(--gray-50)', fontWeight: 600, fontSize: '0.8rem' }}>Score</th>
                        <th style={{ padding: '12px 8px', textAlign: 'left', borderBottom: '2px solid var(--gray-200)', background: 'var(--gray-50)', fontWeight: 600, fontSize: '0.8rem' }}>Result</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredExams.map((e, i) => {
                        const pct = Math.round((e.score / e.total) * 100);
                        const cls = pct >= 80 ? 'badge-green' : pct >= 60 ? 'badge-blue' : 'badge-red';
                        const label = pct >= 80 ? 'Pass' : 'Needs Work';
                        return (
                          <tr key={i}>
                            <td>{fmtDate(e._timestamp)}</td>
                            <td>Set 1</td>
                            <td>{e.categoryName || e.category || '—'}</td>
                            <td><strong>{e.score}/{e.total}</strong></td>
                            <td><span className={`badge ${cls}`}>{pct}% — {label}</span></td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default UserDashboard;