import React from 'react';
import { ExamQuestion } from '../types';

// Flexible question type - supports multiple formats
// Local format: { q, opts, ans, explain? }
// Database format: same as local but with required explain
interface QuestionData {
  q: string;
  opts: string[];
  ans: number;
  explain?: string; // Optional - will be used if provided
}

interface QuestionCardProps {
  question: QuestionData;
  qIdx: number;
  isChecked: boolean;
  selected?: number;
  explanation?: string; // Override explanation
  onSelectAnswer: (qIdx: number, optIdx: number) => void;
  isPracticeMode?: boolean;
  onCheckAnswer?: (qIdx: number) => void;
}

const QuestionCard: React.FC<QuestionCardProps> = ({
  question,
  qIdx,
  isChecked,
  selected,
  explanation: overrideExplanation,
  onSelectAnswer,
  isPracticeMode,
  onCheckAnswer
}) => {
  const isCorrect = selected === question.ans;
  const isUnanswered = selected === undefined;
  // Use override if provided, otherwise use question's explain
  const explanation = overrideExplanation || question.explain || '';

  const handleCheckAnswer = () => {
    if (onCheckAnswer) {
      onCheckAnswer(qIdx);
    }
  };

  return (
    <div className="q-card">
      <div className="q-header">
        <div className="q-num">{qIdx + 1}</div>
        <div className="q-text" style={{ whiteSpace: 'pre-wrap' }}>{question.q}</div>
      </div>
      <div className="q-options">
        {question.opts.map((opt, optIdx) => {
          let cls = '';
          if (isChecked) {
            if (optIdx === question.ans) cls = 'correct';
            else if (optIdx === selected && !isCorrect) cls = 'wrong';
          } else if (optIdx === selected) {
            cls = 'selected';
          }
          return (
            <div
              key={optIdx}
              className={`q-opt${cls ? ' ' + cls : ''}`}
              onClick={() => !isChecked && onSelectAnswer(qIdx, optIdx)}
              style={isChecked ? { pointerEvents: 'none' } : {}}
            >
              <input type="radio" readOnly checked={optIdx === selected} />
              <span style={{ whiteSpace: 'pre-wrap' }}>{String.fromCharCode(65 + optIdx)}. {opt}</span>
            </div>
          );
        })}
      </div>
      
      {isPracticeMode && !isChecked && selected !== undefined && (
        <div style={{ marginTop: '16px', textAlign: 'center' }}>
          <button 
            className="btn btn-blue"
            onClick={handleCheckAnswer}
          >
            Check Answer
          </button>
        </div>
      )}
      
      {isChecked ? (
        <div className={`q-answer-box show ${isCorrect ? 'correct-ans' : 'wrong-ans'}`}>
          {isCorrect
            ? <><strong>✅ Correct!</strong></>
            : isUnanswered
              ? <><strong>⚠️ Not Answered.</strong> Correct answer: <strong>{String.fromCharCode(65 + question.ans)}. {question.opts[question.ans]}</strong></>
              : <><strong>❌ Incorrect.</strong> Correct answer: <strong>{String.fromCharCode(65 + question.ans)}. {question.opts[question.ans]}</strong></>
          }
          {explanation && (
            <div style={{ 
              marginTop: '16px', 
              padding: '16px', 
              background: 'var(--blue-pale)', 
              borderRadius: 'var(--radius)',
              border: '1px solid var(--blue-soft)'
            }}>
              <pre style={{ 
                whiteSpace: 'pre-wrap', 
                fontFamily: 'inherit',
                fontSize: '0.85rem',
                color: 'var(--gray-700)',
                margin: 0
              }}>
                {explanation}
              </pre>
            </div>
          )}
        </div>
      ) : null}
    </div>
  );
};

export default QuestionCard;