import React, { useState, useCallback, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import Layout from '../components/Layout';
import Toast from '../components/Toast';
import QuestionCard from '../components/QuestionCard';
import { useToast } from '../hooks/useToast';
import { saveRecord } from '../utils/storage';
import { SAP_EXAM_DATA, EXPLANATIONS, SAPQuestion, EXAM_SETS, getSetQuestions, getSetQuestionCount } from '../data/sapQuestions';

// Fisher-Yates shuffle algorithm
const shuffleArray = <T,>(array: T[]): T[] => {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
};

type Step = 'intro' | 'select-set' | 'exam' | 'result';
type ExamMode = 'practice' | 'exam' | null;

const SAPExamPage: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  // Auth check
  useEffect(() => {
    const isLoggedIn = sessionStorage.getItem('userLoggedIn') === '1' && sessionStorage.getItem('dashUser');
    if (!isLoggedIn) {
      navigate('/login', { replace: true });
    }
  }, [navigate]);

  // Check for mode and set in URL params - redirect to select-set if set is missing, or go to exam if set is provided
  useEffect(() => {
    const mode = searchParams.get('mode');
    const setId = searchParams.get('set');
    
    // If both mode and set are provided, go to exam with those values
    if ((mode === 'practice' || mode === 'exam') && setId) {
      setExamMode(mode);
      setSelectedSet(parseInt(setId, 10));
      setStep('exam');
    }
    // If mode is provided but no set is selected, go to select-set
    else if ((mode === 'practice' || mode === 'exam') && !setId) {
      setExamMode(mode);
      setStep('select-set');
    }
  }, [searchParams]);

  const [step, setStep] = useState<Step>('intro');
  const [selectedSet, setSelectedSet] = useState<number>(1);
  const [examMode, setExamMode] = useState<ExamMode>(null);
  const [userAnswers, setUserAnswers] = useState<Record<number, number>>({});
  const [checked, setChecked] = useState<Record<number, boolean>>({});
  const [showDetailedExplanation, setShowDetailedExplanation] = useState<Record<number, boolean>>({});
  const [expandedQuestions, setExpandedQuestions] = useState<Record<number, boolean>>({});
  const [submitted, setSubmitted] = useState(false);
  const [scoreData, setScoreData] = useState<{ score: number; total: number } | null>(null);
  const [filter, setFilter] = useState<'all' | 'correct' | 'incorrect' | 'unanswered'>('all');
  const { msg, type, visible, showToast } = useToast();

  // Shuffle questions on first render
  const [questionOrder, setQuestionOrder] = useState<number[]>([]);
  const [shuffledQuestions, setShuffledQuestions] = useState<SAPQuestion[]>([]);

  useEffect(() => {
    // Get questions for the selected set
    const questions = getSetQuestions(selectedSet);
    const order = Array.from({ length: questions.length }, (_, i) => i);
    // Only shuffle for exam mode, keep fixed for practice
    const shuffledOrder = examMode === 'exam' ? shuffleArray(order) : order;
    setQuestionOrder(shuffledOrder);
    setShuffledQuestions(shuffledOrder.map(i => questions[i]));
  }, [examMode, selectedSet]);

  const data = SAP_EXAM_DATA;
  const totalQ = data?.questions.length ?? 1;

  const selectAnswer = (qIdx: number, optIdx: number) => {
    if (checked[qIdx]) return;
    // Map shuffled index to original index for storing
    const originalIdx = questionOrder[qIdx];
    setUserAnswers(prev => ({ ...prev, [originalIdx]: optIdx }));
  };

  const checkAnswer = (qIdx: number) => {
    if (userAnswers[qIdx] === undefined) {
      showToast('⚠️ Please select an answer first.', 'error');
      return;
    }
    setChecked(prev => ({ ...prev, [qIdx]: true }));
  };

  const showAnswerDirect = (qIdx: number) => {
    // For practice mode, map shuffled index to original
    const originalIdx = questionOrder[qIdx];
    setChecked(prev => ({ ...prev, [originalIdx]: true }));
  };

  const toggleDetailedExplanation = (qIdx: number) => {
    setShowDetailedExplanation(prev => ({ ...prev, [qIdx]: !prev[qIdx] }));
  };

  const toggleExpandQuestion = (qIdx: number) => {
    setExpandedQuestions(prev => ({ ...prev, [qIdx]: !prev[qIdx] }));
  };

  const submitExam = useCallback(() => {
    const total = shuffledQuestions.length;
    let score = 0;

    const allChecked: Record<number, boolean> = {};
    shuffledQuestions.forEach((_, i) => { allChecked[i] = true; });
    setChecked(allChecked);
    setSubmitted(true);

    // Score based on shuffled order - map back to original question
    shuffledQuestions.forEach((q, i) => {
      const originalIdx = questionOrder[i];
      if (userAnswers[originalIdx] !== undefined && userAnswers[originalIdx] === q.ans) score++;
    });

    saveRecord('exam_submissions', {
      category: 'sap',
      categoryName: data.name,
      score,
      total,
      percentage: Math.round(score / total * 100),
      answers: { ...userAnswers },
      source: 'sap_exam',
    });

    // Clear URL params after submission
    setSearchParams({});

    setScoreData({ score, total });
    setStep('result');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [data, userAnswers, shuffledQuestions, questionOrder, setSearchParams]);

  const answeredCount = Object.keys(userAnswers).length;
  const progressPct = Math.round((answeredCount / totalQ) * 100);

  return (
    <Layout>
      <Toast msg={msg} type={type} visible={visible} />

      <div className="page-hero">
        <span className="section-tag">AWS SAP-C02</span>
        <h1>Solutions Architect <span className="text-blue">Professional</span></h1>
        <p>Practice questions for the AWS SAP-C02 certification exam.</p>
      </div>

      <div className="section">
        <div className="container" style={{ maxWidth: '1100px' }}>

          {/* STEP 1: Introduction */}
          {step === 'intro' && (
            <div style={{ textAlign: 'center', padding: '40px 20px' }}>
              <div style={{ fontSize: '4rem', marginBottom: '20px' }}>{data.emoji}</div>
              <h2 style={{ fontSize: '2rem', fontWeight: 800, marginBottom: '16px', color: 'var(--gray-800)' }}>{data.name}</h2>
              <p style={{ fontSize: '1.1rem', color: 'var(--gray-600)', marginBottom: '32px' }}>
                Test your knowledge with {shuffledQuestions.length} practice questions.
              </p>
              
              <div style={{ display: 'flex', gap: '16px', justifyContent: 'center', flexWrap: 'wrap' }}>
                <button 
                  className="btn btn-blue btn-lg" 
                  onClick={() => {
                    setExamMode('practice');
                    setStep('select-set');
                  }}
                  style={{ minWidth: '200px' }}
                >
                  📝 Practice Mode
                </button>
                <button 
                  className="btn btn-outline btn-lg" 
                  onClick={() => {
                    setExamMode('exam');
                    setStep('select-set');
                  }}
                  style={{ minWidth: '200px' }}
                >
                  🎯 Exam Mode
                </button>
              </div>
              
              <div style={{ marginTop: '40px', padding: '20px', background: 'var(--blue-pale)', borderRadius: 'var(--radius)', maxWidth: '500px', margin: '40px auto 0' }}>
                <h3 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: '12px', color: 'var(--blue-dark)' }}>📚 About This Exam</h3>
                <ul style={{ textAlign: 'left', fontSize: '0.9rem', color: 'var(--gray-700)', paddingLeft: '20px', lineHeight: '1.8' }}>
                  <li>{shuffledQuestions.length} multiple-choice questions</li>
                  <li>Questions shuffled each attempt</li>
                  <li>Detailed explanations after each answer</li>
                  <li>Review all questions at the end</li>
                </ul>
              </div>
            </div>
          )}


          {/* STEP 1b: Select Exam Set */}
          {step === 'select-set' && (
            <div style={{ textAlign: 'center', padding: '40px 20px' }}>
              <h2 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: '8px' }}>Select Exam Set</h2>
              <p style={{ marginBottom: '8px', color: 'var(--gray-600)' }}>
                {examMode === 'practice' ? '📝 Practice Mode' : examMode === 'exam' ? '🎯 Exam Mode' : ''} — Choose a set of questions
              </p>
              <p style={{ marginBottom: '32px', color: 'var(--gray-500)', fontSize: '0.85rem' }}>
                {examMode === 'practice' ? 'Questions stay in order, see answers after each question' : 'Questions are shuffled,Submit all at once'}
              </p>
              
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', maxWidth: '400px', margin: '0 auto' }}>
                {EXAM_SETS.map(set => (
                  <button
                    key={set.id}
                    onClick={() => {
                      setSelectedSet(set.id);
                      // Update URL with mode and set params
                      const currentMode = searchParams.get('mode') || examMode;
                      setSearchParams({ mode: currentMode || 'practice', set: set.id.toString() });
                      setStep('exam');
                    }}
                    disabled={getSetQuestionCount(set.id) === 0}
                    className={`btn ${selectedSet === set.id ? 'btn-blue' : 'btn-outline'} btn-lg`}
                    style={{ justifyContent: 'space-between', padding: '16px 24px' }}
                  >
                    <span>{set.name}</span>
                    <span style={{ fontSize: '0.85rem', opacity: 0.7 }}>{getSetQuestionCount(set.id)}/{set.questions} questions</span>
                  </button>
                ))}
              </div>
              
              <button 
                className="btn btn-link" 
                onClick={() => {
                  setSearchParams({});
                  navigate('/dashboard');
                }}
                style={{ marginTop: '24px' }}
              >
                ← Back to Dashboard
              </button>
            </div>
          )}

          {/* STEP 2: Questions */}
          {step === 'exam' && data && (
            <div>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '20px', flexWrap: 'wrap', gap: '10px' }}>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontSize: '0.78rem', color: 'var(--gray-400)', fontWeight: 600 }}>
                    {answeredCount} of {totalQ} answered
                  </div>
                  <div className="progress-bar-wrap" style={{ width: '180px', marginTop: '5px' }}>
                    <div className="progress-bar-fill" style={{ width: `${progressPct}%` }} />
                  </div>
                </div>
              </div>

              {shuffledQuestions.map((q, qIdx) => (
                <QuestionCard
                  key={qIdx}
                  question={q}
                  qIdx={qIdx}
                  isChecked={checked[questionOrder[qIdx]]}
                  selected={userAnswers[questionOrder[qIdx]]}
                  explanation={EXPLANATIONS[questionOrder[qIdx]]}
                  onSelectAnswer={selectAnswer}
                  isPracticeMode={examMode === 'practice'}
                  onCheckAnswer={showAnswerDirect}
                />
              ))}

              <div style={{ marginTop: '24px', textAlign: 'center' }}>
                {examMode === 'exam' && (
                  <button className="btn btn-blue btn-lg" onClick={submitExam}>
                    {answeredCount < totalQ ? `Submit (${answeredCount}/${totalQ} answered)` : 'Submit & See Results'}
                  </button>
                )}
              </div>
            </div>
          )}

          {/* STEP 3: Results */}
          {step === 'result' && scoreData && (
            <div>
              {/* Score Card */}
              <div style={{ background: 'linear-gradient(135deg, var(--blue-pale), var(--orange-pale))', border: '1px solid var(--gray-200)', borderRadius: 'var(--radius-lg)', padding: '32px', marginBottom: '24px', textAlign: 'center' }}>
                <div style={{ fontSize: '3rem', marginBottom: '12px' }}>
                  {scoreData.score / scoreData.total >= 0.8 ? '🎉' : '📚'}
                </div>
                <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--gray-800)', marginBottom: '8px' }}>
                  Your Score: {scoreData.score}/{scoreData.total}
                </h2>
                <p style={{ fontSize: '1.1rem', fontWeight: 700, color: scoreData.score / scoreData.total >= 0.8 ? 'var(--green)' : 'var(--orange)' }}>
                  {Math.round(scoreData.score / scoreData.total * 100)}% — {scoreData.score / scoreData.total >= 0.8 ? 'Excellent!' : 'Keep practicing!'}
                </p>
              </div>

              {/* Review All Questions */}
              <h3 style={{ fontSize: '1.2rem', fontWeight: 800, marginBottom: '16px', marginTop: '32px' }}>📝 Review All Questions</h3>
              
              {/* Filter Buttons */}
              <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', flexWrap: 'wrap' }}>
                <button onClick={() => setFilter('all')} style={{ padding: '8px 16px', borderRadius: '20px', border: filter === 'all' ? '2px solid var(--blue)' : '1px solid var(--gray-300)', background: filter === 'all' ? 'var(--blue)' : '#fff', color: filter === 'all' ? '#fff' : 'var(--gray-700)', cursor: 'pointer' }}>All</button>
                <button onClick={() => setFilter('correct')} style={{ padding: '8px 16px', borderRadius: '20px', border: filter === 'correct' ? '2px solid var(--green)' : '1px solid var(--gray-300)', background: filter === 'correct' ? 'var(--green)' : '#fff', color: filter === 'correct' ? '#fff' : 'var(--gray-700)', cursor: 'pointer' }}>Correct</button>
                <button onClick={() => setFilter('incorrect')} style={{ padding: '8px 16px', borderRadius: '20px', border: filter === 'incorrect' ? '2px solid var(--red)' : '1px solid var(--gray-300)', background: filter === 'incorrect' ? 'var(--red)' : '#fff', color: filter === 'incorrect' ? '#fff' : 'var(--gray-700)', cursor: 'pointer' }}>Incorrect</button>
                <button onClick={() => setFilter('unanswered')} style={{ padding: '8px 16px', borderRadius: '20px', border: filter === 'unanswered' ? '2px solid var(--orange)' : '1px solid var(--gray-300)', background: filter === 'unanswered' ? 'var(--orange)' : '#fff', color: filter === 'unanswered' ? '#fff' : 'var(--gray-700)', cursor: 'pointer' }}>Not Answered</button>
                <button onClick={() => {
                  const allExpanded = Object.values(expandedQuestions).every(v => v);
                  setExpandedQuestions(allExpanded ? {} : Object.fromEntries(data.questions.map((_, i) => [i, true])));
                }} style={{ padding: '8px 16px', borderRadius: '20px', border: '1px solid var(--gray-300)', background: '#fff', color: 'var(--gray-700)', cursor: 'pointer', marginLeft: 'auto' }}>
                  {Object.values(expandedQuestions).every(v => v) ? 'Collapse All' : 'Expand All'}
                </button>
              </div>
              
              {shuffledQuestions.map((q, qIdx) => {
                const originalIdx = questionOrder[qIdx];
                const userAns = userAnswers[originalIdx];
                const isCorrect = userAns !== undefined && userAns === q.ans;
                const isUnanswered = userAns === undefined;
                const detailedExp = EXPLANATIONS[originalIdx];
                const isExpanded = expandedQuestions[qIdx];
                
                if (filter === 'correct' && !isCorrect) return null;
                if (filter === 'incorrect' && (isCorrect || isUnanswered)) return null;
                if (filter === 'unanswered' && !isUnanswered) return null;
                
                return (
                  <div key={qIdx} style={{ background: '#fff', border: '1.5px solid var(--gray-200)', borderRadius: 'var(--radius)', padding: '20px', marginBottom: '12px' }}>
                    {/* Collapsible Header */}
                    <div 
                      onClick={() => toggleExpandQuestion(qIdx)}
                      style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
                    >
                      <span style={{ fontWeight: 700, fontSize: '1.1rem', color: isCorrect ? 'var(--green)' : isUnanswered ? 'var(--orange)' : 'var(--red)' }}>
                        {isCorrect ? '✅ Correct' : isUnanswered ? '⚠️ Not Answered' : '❌ Incorrect'} - Question {qIdx + 1}
                      </span>
                      <span style={{ fontSize: '1.2rem' }}>{isExpanded ? '▲' : '▼'}</span>
                    </div>
                    
                    {/* Expandable Content */}
                    {isExpanded && (
                      <div style={{ marginTop: '16px' }}>
                        <div style={{ fontSize: '0.9rem', marginBottom: '12px', fontWeight: 600, whiteSpace: 'pre-wrap' }}>{q.q}</div>
                        <div style={{ fontSize: '0.85rem', color: 'var(--gray-600)', marginBottom: '8px' }}>
                          <span>Your Answer: {userAns !== undefined ? String.fromCharCode(65 + userAns) + '. ' + q.opts[userAns] : 'Not answered'}</span>
                        </div>
                        {!isCorrect && !isUnanswered && (
                          <div style={{ fontSize: '0.85rem', color: 'var(--green)', marginBottom: '8px' }}>
                            Correct Answer: {String.fromCharCode(65 + q.ans) + '. ' + q.opts[q.ans]}
                          </div>
                        )}
                        {isUnanswered && (
                          <div style={{ fontSize: '0.85rem', color: 'var(--green)', marginBottom: '8px' }}>
                            Correct Answer: {String.fromCharCode(65 + q.ans) + '. ' + q.opts[q.ans]}
                          </div>
                        )}
                        {detailedExp && (
                          <div style={{ marginTop: '12px', padding: '14px', background: 'var(--blue-pale)', borderRadius: 'var(--radius-sm)', border: '1px solid var(--blue-soft)' }}>
                            <div style={{ fontWeight: 700, fontSize: '0.95rem', marginBottom: '8px', color: 'var(--blue-dark)' }}>📚 Explanation</div>
                            <pre style={{ whiteSpace: 'pre-wrap', fontFamily: 'inherit', fontSize: '0.95rem', color: 'var(--gray-700)', margin: 0 }}>
                              {detailedExp}
                            </pre>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default SAPExamPage;
